import React, { useState, useEffect } from 'react';
import { Link as RouterLink } from 'react-router-dom';
import {
  Box,
  Button,
  Container,
  Typography,
  Grid,
  Card,
  CardContent,
  Stack,
  Paper,
  useTheme,
  Avatar,
  Chip,
  Fade,
  Divider,
  IconButton,
  useMediaQuery,
  TextField,
  CircularProgress
} from '@mui/material';
import AutoAwesomeIcon from '@mui/icons-material/AutoAwesome';
import ArrowForwardIcon from '@mui/icons-material/ArrowForward';
import StarIcon from '@mui/icons-material/Star';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import PlayArrowIcon from '@mui/icons-material/PlayArrow';
import VerifiedUserIcon from '@mui/icons-material/VerifiedUser';
import FormatQuoteIcon from '@mui/icons-material/FormatQuote';

const HomePage = () => {
  const theme = useTheme();
  const isMobile = useMediaQuery(theme.breakpoints.down('md'));

  // Interactive demo state
  const [demoStage, setDemoStage] = useState(0);
  const [isAnimating, setIsAnimating] = useState(false);

  // Auto-advance demo stages
  useEffect(() => {
    const timer = setTimeout(() => {
      setIsAnimating(true);
      setTimeout(() => {
        setDemoStage(1);
        setTimeout(() => {
          setDemoStage(2);
          setTimeout(() => {
            setDemoStage(3);
            setTimeout(() => {
              // Reset demo after showing all stages
              setIsAnimating(false);
              setDemoStage(0);
            }, 4000);
          }, 3000);
        }, 3000);
      }, 2000);
    }, 1000);

    return () => clearTimeout(timer);
  }, [demoStage === 0 && !isAnimating]);

  return (
    <Box sx={{ overflow: 'hidden' }}>
      {/* Hero Section */}
      <Box 
        sx={{
          pt: { xs: 8, md: 10 },
          pb: { xs: 10, md: 12 },
          position: 'relative',
        }}
      >
        {/* Background gradient */}
        <Box 
          sx={{
            position: 'absolute',
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            background: 'linear-gradient(180deg, rgba(93, 95, 239, 0.05) 0%, rgba(93, 95, 239, 0) 100%)',
            zIndex: -1
          }}
        />

        <Container maxWidth="lg">
          <Grid container spacing={6} alignItems="center">
            {/* Left side - Hero text */}
            <Grid item xs={12} md={6}>
              <Chip
                icon={<AutoAwesomeIcon />}
                label="AI-Powered Testimonials"
                sx={{ 
                  mb: 3, 
                  bgcolor: 'primary.light', 
                  color: 'primary.dark',
                  fontWeight: 600,
                  '& .MuiChip-icon': { color: 'primary.main' }
                }}
              />

              <Typography 
                variant="h2" 
                component="h1" 
                gutterBottom
                sx={{ 
                  fontWeight: 700,
                  fontSize: { xs: '2.5rem', md: '3.5rem' },
                  lineHeight: 1.2
                }}
              >
                Turn <Box component="span" sx={{ color: 'primary.main' }}>"It was good"</Box> into testimonials that sell
              </Typography>

              <Typography variant="subtitle1" color="text.secondary" sx={{ mb: 4, fontSize: '1.1rem' }}>
                Enhance bland client feedback into compelling stories that showcase your true impact—with AI that captures transformation, emotion, and results.
              </Typography>

              <Stack direction={{ xs: 'column', sm: 'row' }} spacing={2}>
                <Button 
                  variant="contained" 
                  color="primary"
                  size="large"
                  component={RouterLink}
                  to="/enhance"
                  sx={{ px: 3, py: 1.5 }}
                  endIcon={<ArrowForwardIcon />}
                >
                  Enhance a Testimonial
                </Button>

                <Button 
                  variant="outlined" 
                  color="primary"
                  size="large"
                  startIcon={<PlayArrowIcon />}
                  sx={{ px: 3, py: 1.5 }}
                  onClick={() => {
                    setDemoStage(0);
                    setIsAnimating(true);
                  }}
                >
                  See How It Works
                </Button>
              </Stack>

              <Box sx={{ display: 'flex', alignItems: 'center', mt: 4 }}>
                <Box sx={{ display: 'flex', mr: 1.5 }}>
                  {[...Array(5)].map((_, i) => (
                    <StarIcon key={i} sx={{ color: '#FFD700', fontSize: 20 }} />
                  ))}
                </Box>
                <Typography variant="body2" color="text.secondary">
                  <Box component="span" sx={{ fontWeight: 600, color: 'text.primary' }}>4.9/5</Box> from 200+ users
                </Typography>
              </Box>
            </Grid>

            {/* Right side - Interactive Demo */}
            <Grid item xs={12} md={6}>
              <Box 
                sx={{ 
                  position: 'relative', 
                  height: 400,
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center'
                }}
              >
                {/* Original testimonial card */}
                <Fade in={demoStage >= 0} timeout={1000}>
                  <Paper
                    elevation={3}
                    sx={{
                      position: 'absolute',
                      top: 20,
                      left: 0,
                      width: '80%',
                      p: 3,
                      borderRadius: 3,
                      bgcolor: 'white',
                      zIndex: 3,
                      border: '1px solid rgba(0,0,0,0.08)',
                      transform: demoStage >= 1 ? 'translateY(-10px)' : 'none',
                      transition: 'transform 0.5s ease-in-out',
                    }}
                  >
                    <Box sx={{ display: 'flex', alignItems: 'center', mb: 2 }}>
                      <FormatQuoteIcon sx={{ color: 'text.disabled', mr: 1 }} />
                      <Typography variant="overline" color="text.secondary" fontWeight={600}>
                        ORIGINAL TESTIMONIAL
                      </Typography>
                    </Box>
                    <Typography variant="body1" color="text.secondary">
                      "The coaching was good. I learned some things that helped me."
                    </Typography>
                  </Paper>
                </Fade>

                {/* Connecting line 1 */}
                <Fade in={demoStage >= 1} timeout={1000}>
                  <Box sx={{
                    position: 'absolute',
                    top: 120,
                    left: '40%',
                    height: 60,
                    width: 2,
                    bgcolor: 'primary.main',
                    zIndex: 1,
                    '&::after': {
                      content: '""',
                      position: 'absolute',
                      bottom: 0,
                      left: -4,
                      width: 10,
                      height: 10,
                      borderRadius: '50%',
                      bgcolor: 'primary.main',
                    }
                  }} />
                </Fade>

                {/* AI Enhancement card */}
                <Fade in={demoStage >= 1} timeout={1000}>
                  <Paper
                    elevation={3}
                    sx={{
                      position: 'absolute',
                      top: 180,
                      left: '20%',
                      width: '80%',
                      p: 3,
                      borderRadius: 3,
                      bgcolor: 'primary.light',
                      color: 'primary.dark',
                      zIndex: 3,
                      border: '1px solid rgba(93, 95, 239, 0.3)',
                      transform: demoStage >= 2 ? 'translateY(-10px)' : 'none',
                      transition: 'transform 0.5s ease-in-out',
                    }}
                  >
                    <Box sx={{ display: 'flex', alignItems: 'center', mb: 2 }}>
                      <AutoAwesomeIcon sx={{ color: 'primary.main', mr: 1 }} />
                      <Typography variant="overline" color="primary.main" fontWeight={600}>
                        AI-ENHANCED
                      </Typography>
                    </Box>
                    <Typography variant="body1" fontWeight={500}>
                      "Working with Sarah transformed my approach to challenges. I went from feeling stuck to landing two major clients in just 3 weeks. Her coaching didn't just teach me tactics—it changed my entire mindset about what's possible."
                    </Typography>
                  </Paper>
                </Fade>

                {/* Connecting line 2 */}
                <Fade in={demoStage >= 2} timeout={1000}>
                  <Box sx={{
                    position: 'absolute',
                    top: 280,
                    left: '60%',
                    height: 60,
                    width: 2,
                    bgcolor: 'success.main',
                    zIndex: 1,
                    '&::after': {
                      content: '""',
                      position: 'absolute',
                      bottom: 0,
                      left: -4,
                      width: 10,
                      height: 10,
                      borderRadius: '50%',
                      bgcolor: 'success.main',
                    }
                  }} />
                </Fade>

                {/* Verification card */}
                <Fade in={demoStage >= 2} timeout={1000}>
                  <Paper
                    elevation={3}
                    sx={{
                      position: 'absolute',
                      top: 340,
                      left: '40%',
                      width: '80%',
                      p: 3,
                      borderRadius: 3,
                      bgcolor: 'success.light',
                      color: 'success.dark',
                      zIndex: 3,
                      border: '1px solid rgba(16, 185, 129, 0.3)',
                    }}
                  >
                    <Box sx={{ display: 'flex', alignItems: 'center', mb: 1 }}>
                      <VerifiedUserIcon sx={{ color: 'success.main', mr: 1 }} />
                      <Typography variant="overline" color="success.main" fontWeight={600}>
                        CLIENT VERIFIED
                      </Typography>
                    </Box>
                    <Typography variant="body2" fontWeight={500}>
                      {demoStage >= 3 ? "Testimonial approved by client and ready to use!" : "Sending verification link to client..."}
                    </Typography>
                    {demoStage >= 3 && (
                      <Chip 
                        icon={<CheckCircleIcon />} 
                        label="Approved" 
                        color="success" 
                        size="small" 
                        sx={{ mt: 1 }} 
                      />
                    )}
                  </Paper>
                </Fade>

                {/* New Trigger button (similar to byedispute.com) */}
                <Fade in={!isAnimating} timeout={500}>
                  <Button
                    variant="outlined"
                    size="small"
                    sx={{
                      position: 'absolute',
                      bottom: -30,
                      right: 0,
                      borderRadius: 20,
                      px: 2,
                      py: 0.5,
                      fontSize: '0.75rem',
                      color: 'text.secondary',
                      borderColor: 'divider',
                      '&:hover': {
                        bgcolor: 'rgba(0,0,0,0.03)',
                        borderColor: 'divider'
                      }
                    }}
                    onClick={() => {
                      setDemoStage(0);
                      setIsAnimating(true);
                    }}
                    startIcon={<AutoAwesomeIcon sx={{ fontSize: '1rem' }} />}
                  >
                    New Example
                  </Button>
                </Fade>
              </Box>
            </Grid>
          </Grid>
        </Container>
      </Box>

      {/* How It Works Section */}
      <Box sx={{ py: 10, bgcolor: 'background.default' }}>
        <Container maxWidth="lg">
          <Typography variant="h2" align="center" gutterBottom>
            How It Works
          </Typography>
          <Typography variant="subtitle1" align="center" color="text.secondary" sx={{ mb: 8, maxWidth: 700, mx: 'auto' }}>
            Transform bland testimonials into powerful stories in three simple steps
          </Typography>

          <Grid container spacing={4}>
            <Grid item xs={12} sm={6} md={4}>
              <Card 
                elevation={0} 
                sx={{ 
                  height: '100%',
                  p: 3,
                  borderRadius: 3,
                  border: '1px solid rgba(0, 0, 0, 0.08)',
                  transition: 'all 0.3s ease',
                  '&:hover': {
                    transform: 'translateY(-5px)',
                    boxShadow: '0 10px 30px rgba(0, 0, 0, 0.1)'
                  }
                }}
              >
                <Box 
                  sx={{ 
                    width: 50, 
                    height: 50, 
                    borderRadius: '50%', 
                    bgcolor: 'primary.light',
                    color: 'primary.main',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    fontWeight: 700,
                    fontSize: '1.5rem',
                    mb: 2
                  }}
                >
                  1
                </Box>
                <Typography variant="h5" gutterBottom>
                  Submit raw testimonial
                </Typography>
                <Typography variant="body1" color="text.secondary">
                  Paste your client's original words, no matter how brief or bland they might be.
                </Typography>
              </Card>
            </Grid>

            <Grid item xs={12} sm={6} md={4}>
              <Card 
                elevation={0} 
                sx={{ 
                  height: '100%',
                  p: 3,
                  borderRadius: 3,
                  border: '1px solid rgba(0, 0, 0, 0.08)',
                  transition: 'all 0.3s ease',
                  '&:hover': {
                    transform: 'translateY(-5px)',
                    boxShadow: '0 10px 30px rgba(0, 0, 0, 0.1)'
                  }
                }}
              >
                <Box 
                  sx={{ 
                    width: 50, 
                    height: 50, 
                    borderRadius: '50%', 
                    bgcolor: 'primary.light',
                    color: 'primary.main',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    fontWeight: 700,
                    fontSize: '1.5rem',
                    mb: 2
                  }}
                >
                  2
                </Box>
                <Typography variant="h5" gutterBottom>
                  Get AI-enhanced version
                </Typography>
                <Typography variant="body1" color="text.secondary">
                  Our AI extracts the transformation, emotion, and impact from your client's experience.
                </Typography>
              </Card>
            </Grid>

            <Grid item xs={12} sm={6} md={4}>
              <Card 
                elevation={0} 
                sx={{ 
                  height: '100%',
                  p: 3,
                  borderRadius: 3,
                  border: '1px solid rgba(0, 0, 0, 0.08)',
                  transition: 'all 0.3s ease',
                  '&:hover': {
                    transform: 'translateY(-5px)',
                    boxShadow: '0 10px 30px rgba(0, 0, 0, 0.1)'
                  }
                }}
              >
                <Box 
                  sx={{ 
                    width: 50, 
                    height: 50, 
                    borderRadius: '50%', 
                    bgcolor: 'primary.light',
                    color: 'primary.main',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    fontWeight: 700,
                    fontSize: '1.5rem',
                    mb: 2
                  }}
                >
                  3
                </Box>
                <Typography variant="h5" gutterBottom>
                  One-click client approval
                </Typography>
                <Typography variant="body1" color="text.secondary">
                  Send a verification link to your client for instant approval with a single click.
                </Typography>
              </Card>
            </Grid>
          </Grid>
        </Container>
      </Box>

      {/* CTA Section */}
      <Box sx={{ py: 10 }}>
        <Container maxWidth="md">
          <Card 
            sx={{ 
              p: { xs: 4, md: 6 },
              background: 'linear-gradient(135deg, #5D5FEF 0%, #7879F1 100%)',
              color: 'white',
              textAlign: 'center',
              position: 'relative',
              overflow: 'hidden',
              borderRadius: 4
            }}
          >
            <Box 
              sx={{
                position: 'absolute',
                top: 0,
                left: 0,
                right: 0,
                bottom: 0,
                opacity: 0.1,
                backgroundImage: 'radial-gradient(circle, #ffffff 1px, transparent 1px)',
                backgroundSize: '20px 20px'
              }}
            />

            <Typography variant="h3" gutterBottom>
              Ready to transform your testimonials?
            </Typography>
            <Typography variant="subtitle1" sx={{ mb: 4, opacity: 0.9, maxWidth: 600, mx: 'auto' }}>
              Start free, no credit card required. Upgrade when you need more.
            </Typography>
            <Button 
              variant="contained" 
              size="large"
              component={RouterLink}
              to="/enhance"
              sx={{ 
                px: 4, 
                py: 1.5,
                bgcolor: 'white',
                color: 'primary.main',
                '&:hover': {
                  bgcolor: 'rgba(255, 255, 255, 0.9)'
                }
              }}
            >
              Get Started Now
            </Button>
          </Card>
        </Container>
      </Box>
    </Box>
  );
};

export default HomePage;
